CREATE TABLE IF NOT EXISTS vessels (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE RESTRICT, name text NOT NULL, imo text, mmsi text, callsign text, type text NOT NULL CHECK (type IN ('PSV','AHTS','OSRV','CSV','DSV','SURVEY','CREW_BOAT','TUG','SUPPLY','ACCOMMODATION','OTHER')), flag text, status text NOT NULL CHECK (status IN ('AVAILABLE','UNDERWAY','MOORED','MAINTENANCE','UNAVAILABLE')), capacity integer CHECK (capacity IS NULL OR capacity >= 0), operator text, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE (organization_id, name), UNIQUE (organization_id, imo), UNIQUE (organization_id, mmsi));
CREATE TABLE IF NOT EXISTS vessel_positions (id uuid PRIMARY KEY, vessel_id uuid NOT NULL REFERENCES vessels(id) ON DELETE CASCADE, latitude double precision NOT NULL CHECK (latitude BETWEEN -90 AND 90), longitude double precision NOT NULL CHECK (longitude BETWEEN -180 AND 180), speed double precision CHECK (speed IS NULL OR speed >= 0), course double precision CHECK (course IS NULL OR course BETWEEN 0 AND 360), heading double precision CHECK (heading IS NULL OR heading BETWEEN 0 AND 360), navigation_status text, source text NOT NULL DEFAULT 'MANUAL', accuracy double precision CHECK (accuracy IS NULL OR accuracy >= 0), recorded_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS vessel_positions_vessel_recorded_idx ON vessel_positions (vessel_id, recorded_at DESC);
CREATE TABLE IF NOT EXISTS voyages (id uuid PRIMARY KEY, vessel_id uuid NOT NULL REFERENCES vessels(id) ON DELETE RESTRICT, origin_asset_id uuid REFERENCES offshore_assets(id) ON DELETE SET NULL, destination_asset_id uuid REFERENCES offshore_assets(id) ON DELETE SET NULL, planned_departure timestamptz, actual_departure timestamptz, planned_arrival timestamptz, estimated_arrival timestamptz, actual_arrival timestamptz, status text NOT NULL CHECK (status IN ('PLANNED','UNDERWAY','ARRIVED','CANCELLED','DELAYED')), purpose text NOT NULL, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS people (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE RESTRICT, name text NOT NULL, employee_code text NOT NULL, company text, position text, status text NOT NULL CHECK (status IN ('ACTIVE','INACTIVE','SUSPENDED')), contact jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE (organization_id, employee_code));
CREATE TABLE IF NOT EXISTS competencies (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, code text NOT NULL, name text NOT NULL, description text, validity_required boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE (organization_id, code));
CREATE TABLE IF NOT EXISTS person_competencies (id uuid PRIMARY KEY, person_id uuid NOT NULL REFERENCES people(id) ON DELETE CASCADE, competency_id uuid NOT NULL REFERENCES competencies(id) ON DELETE RESTRICT, issued_at date, expires_at date, issuer text, status text NOT NULL CHECK (status IN ('VALID','EXPIRED','SUSPENDED')), document_url text, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE (person_id, competency_id));
CREATE TABLE IF NOT EXISTS people_on_board (id uuid PRIMARY KEY, person_id uuid NOT NULL REFERENCES people(id) ON DELETE RESTRICT, asset_id uuid NOT NULL REFERENCES offshore_assets(id) ON DELETE RESTRICT, embarked_at timestamptz NOT NULL, expected_disembark_at timestamptz, disembarked_at timestamptz, status text NOT NULL CHECK (status IN ('ON_BOARD','DISEMBARKED')), cabin text, shift text, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS people_on_board_active_person_idx ON people_on_board (person_id) WHERE status = 'ON_BOARD';
CREATE INDEX IF NOT EXISTS people_on_board_asset_status_idx ON people_on_board (asset_id, status);
